// Day Counter — calculate NEXT week's number and date range
function getWeekdayDates() {
  const dates = [];
  let d = new Date(Date.UTC(2026, 2, 2));
  while (dates.length < 90) {
    if (d.getUTCDay() !== 0 && d.getUTCDay() !== 6) dates.push(d.toISOString().split('T')[0]);
    d = new Date(d.getTime() + 86400000);
  }
  return dates;
}
const weekdays = getWeekdayDates();
const now = new Date();
const todayStr = now.toLocaleDateString('en-CA', { timeZone: 'Africa/Lagos' });

// Saturday evening: next Monday is 2 days away
// Find the next weekday date > todayStr
let nextWeekdayIdx = -1;
for (let i = 0; i < weekdays.length; i++) {
  if (weekdays[i] > todayStr) { nextWeekdayIdx = i; break; }
}

if (nextWeekdayIdx < 0) nextWeekdayIdx = weekdays.length - 1;
const nextWeekNum = Math.ceil((nextWeekdayIdx + 1) / 5);
const weekStartIdx = (nextWeekNum - 1) * 5;
const weekEndIdx = Math.min(nextWeekNum * 5 - 1, weekdays.length - 1);
const mondayDate = weekdays[weekStartIdx];
const fridayDate = weekdays[weekEndIdx];
const startDayNum = weekStartIdx + 1;
const endDayNum = weekEndIdx + 1;

// NT cycle assignments for each day of the coming week
const NT_14DAY = {
  1: 'Matthew 1-14', 2: 'Matthew 15-28', 3: 'Mark 1-8',
  4: 'Mark 9-16', 5: 'Luke 1-12', 6: 'Luke 13-24',
  7: 'John 1-11', 8: 'John 12-21', 9: 'Acts 1-14',
  10: 'Acts 15-28', 11: 'Romans + 1 Corinthians', 12: '2 Corinthians + Galatians + Ephesians',
  13: 'Philippians through Hebrews', 14: 'James through Revelation'
};

const ntAssignments = [];
for (let i = weekStartIdx; i <= weekEndIdx && i < weekdays.length; i++) {
  const dayNum = i + 1;
  const ntDay = ((dayNum - 1) % 14) + 1;
  ntAssignments.push({ day_num: dayNum, date: weekdays[i], nt_day: ntDay, reading: NT_14DAY[ntDay] });
}

// Days remaining in 90-day plan
const daysRemaining = 90 - endDayNum;

return [{ json: {
  week_num: nextWeekNum, monday_date: mondayDate, friday_date: fridayDate,
  start_day_num: startDayNum, end_day_num: endDayNum,
  nt_assignments: ntAssignments, days_remaining: daysRemaining, date: todayStr
} }];

// Phase Targets — revenue phase and career actions for next week
const dayCounter = $('Day Counter').first().json;
const logs = $('Get Cumulative Stats').all().map(i => i.json);
const allLogs = logs.length > 0 && Array.isArray(logs[0]) ? logs[0] : logs;

let totalRevenue = 0, totalProposals = 0, totalVideos = 0;
let totalBookPages = 0, totalCodeHrs = 0, totalNtChapters = 0;
for (const log of allLogs) {
  if (!log) continue;
  totalRevenue += (log.revenue_today || 0);
  totalProposals += (log.proposals_sent || 0);
  totalVideos += (log.videos_published || 0);
  totalBookPages += (log.book_pages || 0);
  totalCodeHrs += (log.code_hrs || 0);
  totalNtChapters += (log.nt_chapters_read || 0);
}

const weekNum = dayCounter.week_num;
let phase = 1, weeklyTarget = 1000, careerActions = '';
if (weekNum >= 9) {
  phase = 3; weeklyTarget = 20000;
  careerActions = 'Phase 3: Scale mode. Focus on delivery, client management, and high-ticket proposals. Target 3+ active contracts. Ship, invoice, collect.';
} else if (weekNum >= 5) {
  phase = 2; weeklyTarget = 5000;
  careerActions = 'Phase 2: Conversion mode. Follow up on all open proposals. Send 3-5 new proposals daily. Close at least 2 deals this week. Revenue must accelerate.';
} else {
  careerActions = 'Phase 1: Pipeline mode. Send 5+ proposals daily. Cold outreach on LinkedIn/Upwork. Build portfolio pieces. Revenue target is $1K/wk — every dollar counts.';
}

const ntSchedule = dayCounter.nt_assignments.map(a =>
  'Day ' + a.day_num + ' (' + a.date + '): NT Day ' + a.nt_day + ' — ' + a.reading
).join('\n');

const dateRange = dayCounter.monday_date + ' to ' + dayCounter.friday_date;
const subject = 'War Plan · Week ' + weekNum + ' Preview — Phase ' + phase + ' · $' + weeklyTarget.toLocaleString() + '/wk target';

return [{ json: {
  week_num: weekNum, date_range: dateRange, phase, weekly_target: weeklyTarget,
  career_actions: careerActions, nt_schedule: ntSchedule,
  nt_assignments: dayCounter.nt_assignments,
  total_revenue: totalRevenue, total_proposals: totalProposals,
  total_videos: totalVideos, total_book_pages: totalBookPages,
  total_code_hrs: Math.round(totalCodeHrs * 10) / 10,
  days_remaining: dayCounter.days_remaining, subject
} }];

// Build HTML Email — wrap Claude output in styled email template
const stats = $('Phase Targets').first().json;
const aiContent = $('OpenRouter Preview').first().json.choices[0].message.content;
const font = "-apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif";

const html = '<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head>' +
'<body style="margin:0;padding:0;background-color:#07090c;font-family:' + font + ';">' +
'<table role="presentation" width="100%" style="max-width:600px;margin:0 auto;background-color:#07090c;">' +
'<tr><td style="padding:30px 20px;">' +
'<div style="text-align:center;padding:20px 0;border-bottom:2px solid #1a1f2e;">' +
'<h1 style="color:#e2e8f0;font-size:24px;margin:0;">⚔️ War Plan · Week ' + stats.week_num + ' Preview</h1>' +
'<p style="color:#94a3b8;font-size:14px;margin:8px 0 0;">' + stats.date_range + '</p>' +
'<p style="color:#f59e0b;font-size:16px;margin:8px 0 0;">Phase ' + stats.phase + ' · Target: $' + stats.weekly_target.toLocaleString() + '/wk · ' + stats.days_remaining + ' days remaining</p>' +
'</div>' +
'<div style="padding:20px 0;color:#e2e8f0;font-size:14px;line-height:1.6;">' + aiContent + '</div>' +
'<div style="text-align:center;padding:15px 0;border-top:1px solid #1a1f2e;">' +
'<p style="color:#475569;font-size:12px;margin:0;">90-Day War Plan AI Accountability Partner</p>' +
'</div>' +
'</td></tr></table></body></html>';

return [{ json: { subject: stats.subject, html } }];

// Email failed — prepare Telegram fallback
const stats = $('Phase Targets').first().json;
const text = '📧 Week ' + stats.week_num + ' preview email FAILED to send.\n\n' +
  'Phase ' + stats.phase + ' · Target: $' + stats.weekly_target + '/wk\n' +
  stats.days_remaining + ' days remaining in the plan.\n\n' +
  'Check Resend dashboard for error details.';
return [{ json: { fallback_text: text } }];

// AI generation failed — prepare Telegram fallback
const dc = $('Day Counter').first().json;
const text = '📧 Week ' + dc.week_num + ' preview email — AI generation failed.\n' +
  'Next week: Days ' + dc.start_day_num + '-' + dc.end_day_num + ' (' + dc.monday_date + ' to ' + dc.friday_date + ')';
return [{ json: { fallback_text: text } }];
